import {{ Injectable }} from '@nestjs/common';
import {{ NotificationService }} from './models/notification.model';
import {{ NotificationServiceRepository }} from './repositories/notification.repository';

@Injectable()
export class NotificationServiceService {{
  constructor(
    private readonly repository: NotificationServiceRepository,
  ) {{}}

  async findAll(): Promise<NotificationService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<NotificationService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<NotificationService>): Promise<NotificationService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<NotificationService>): Promise<NotificationService> {{
    return this.repository.update(id, data);
  }}
}}

